 1	import * as React from 'react';
 2	import { PageSection, TextInputTypes } from '@patternfly/react-core';
 3	import MultiColumnField from './multi-column-field/MultiColumnField';
 4	import InputField from './multi-column-field/InputField';
 5	
 6	type PipelineParametersProps = {
 7	  addLabel?: string;
 8	  nameLabel: string;
 9	  nameFieldName: string;
10	  descriptionLabel: string;
11	  descriptionFieldName: string;
12	  valueLabel: string;
13	  valueFieldName: string;
14	  emptyMessage: string;
15	  fieldName: string;
16	  emptyValues: { [name: string]: string };
17	  isReadOnly?: boolean;
18	  className?: string;
19	};
20	
21	const PipelineParameters: React.FC<PipelineParametersProps> = ({
22	  addLabel,
23	  nameLabel,
24	  nameFieldName,
25	  descriptionLabel,
26	  descriptionFieldName,
27	  valueLabel,
28	  valueFieldName,
29	  emptyMessage,
30	  fieldName,
31	  emptyValues,
32	  isReadOnly = false,
33	  className,
34	}) => {
35	  return (
36	    <PageSection variant="light" isFilled className={className}>
37	      <MultiColumnField
38	        data-test="pipeline-parameters"
39	        name={fieldName}
40	        addLabel={addLabel}
41	        headers={[
42	          {
43	            name: nameLabel,
44	            required: true,
45	          },
46	          descriptionLabel,
47	          valueLabel,
48	        ]}
49	        emptyValues={emptyValues}
50	        emptyMessage={emptyMessage}
51	        isReadOnly={isReadOnly}
52	      >
53	        <InputField
54	          data-test={nameFieldName}
55	          name={nameFieldName}
56	          type={TextInputTypes.text}
57	          placeholder={nameLabel}
58	          isDisabled={isReadOnly}
59	          aria-label={nameLabel}
60	        />
61	        <InputField
62	          data-test={descriptionFieldName}
63	          name={descriptionFieldName}
64	          type={TextInputTypes.text}
65	          placeholder={descriptionLabel}
66	          isDisabled={isReadOnly}
67	          aria-label={descriptionLabel}
68	        />
69	        <InputField
70	          data-test={valueFieldName}
71	          name={valueFieldName}
72	          type={TextInputTypes.text}
73	          placeholder={valueLabel}
74	          isDisabled={isReadOnly}
75	          aria-label={valueLabel}
76	        />
77	      </MultiColumnField>
78	    </PageSection>
79	  );
80	};
81	
82	export default PipelineParameters;

